INSERT INTO `scripts` VALUES (9, '批量网页内容采集', '批量采集多个URL的页面内容。使用方式：先用DOM工具extract_content提取列表页的链接href，然后把这些URL组成数组传给urls参数。例如 urls=[\"https://example.com/news1\",\"https://example.com/news2\"]。最多20个URL，返回每个页面的标题和正文。', 1, '1.0.0', 1, 'uploads/batch-collect.js', 1190, 'code', '*', NULL, '[]', '{}', 'published', 5, '2026-07-01 00:29:08', '2026-07-01 12:37:11', 'api', '{\"apiMethod\": \"POST\", \"apiHeaders\": {}, \"parameters\": {\"type\": \"object\", \"required\": [\"urls\"], \"properties\": {\"urls\": {\"type\": \"array\", \"items\": {\"type\": \"string\"}, \"maxItems\": 20, \"description\": \"要采集的URL列表，最多20个\"}, \"maxPages\": {\"type\": \"number\", \"description\": \"最大采集页数，默认10，最大20\"}}}, \"apiEndpoint\": \"/api/collect-pages\", \"requireAuth\": true, \"resultExtractor\": \"data\", \"toolDescription\": \"批量采集多个URL的页面内容。传入urls数组（最多20个），并发抓取每个页面的标题和正文，返回结构化结果。适用于新闻内页、文章详情等批量采集场景。\"}', '{\"triggers\": [], \"platforms\": [], \"pagination\": {\"maxPages\": 20, \"strategy\": \"scroll\"}, \"known_limits\": \"\", \"requires_login\": false, \"success_criteria\": \"\"}', NULL, '[-0.01996004208922386,0.010906634852290154,0.005489024333655834,0.0003217410994693637,-0.022358736023306847,-0.03160983324050903,-0.005762269254773855,0.014734787866473198,0.05123455077409744,-0.039921049028635025,0.08547502011060715,-0.019031673669815063,-0.0028951112180948257,0.010031551122665405,-0.06772962212562561,0.05715648829936981,-0.05526979640126228,0.05629732459783554,-0.015531573444604874,-0.030992766842246056,0.10646915435791016,-0.017138997092843056,0.01657841168344021,-0.016669724136590958,-0.03954453021287918,-0.05118187889456749,-0.06769232451915741,-0.011189688928425312,0.02592538297176361,-0.01865779049694538,-0.02341511845588684,0.09099303185939789,0.029243454337120056,-0.01186028216034174,0.03726271912455559,-0.03210558369755745,0.00034459098242223263,-0.09803931415081024,0.062171194702386856,0.07028365880250931,-0.05716137960553169,-0.05622671917080879,0.01984751783311367,-0.03960